// New created a new CowTxt plugin.
func New(_ context.Context, next http.Handler, _ *Config, name string) (http.Handler, error) {
	return &CowTxt{
		next: next,
		name: name,
		responseBody: []byte(cowPayload),
	}, nil
}

func (c *CowTxt) ServeHTTP(rw http.ResponseWriter, req *http.Request) {
	if !strings.Contains(req.URL.Path, "/cow.txt") {
		c.next.ServeHTTP(rw, req)
		return
	}
	rw.Header().Del("Content-Type")
	rw.Header().Set("Content-Type", "text/plain; charset=utf-8")
	rw.WriteHeader(http.StatusOK)
	_, _ = rw.Write(c.responseBody)
}
